import React, { useState } from "react";
import { BrowserRouter as Router, Routes, Route } from "react-router-dom";
import Home from "./Home";
import Men from "./Men";
import Women from "./Women";
import Kids from "./Kids";
import Contact from "./Contact";

function App() {
  const [cartItems, setCartItems] = useState({});

  return (
    <Router>
      <Routes>
        <Route path="/" element={<Home cartItems={cartItems} />} />
        <Route path="/men" element={<Men cartItems={cartItems} setCartItems={setCartItems} />} />
        <Route path="/women" element={<Women cartItems={cartItems} setCartItems={setCartItems} />} />
        <Route path="/kids" element={<Kids cartItems={cartItems} setCartItems={setCartItems} />} />
        <Route path="/contact" element={<Contact />} />
      </Routes>
    </Router>
  );
}

export default App;
